#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum VopPxrprojectorProjection {
    Camera = 0,
    Spherical = 1,
    Cylindrical = 2,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum VopPxrprojectorUse {
    /// Current position: P + N
    CurrentPositionPPlusN = 0,
    /// Undisplaced position: Po + Non
    UndisplacedPositionPoPlusNon = 1,
    /// Deform : __Pref + __Nref
    DeformPrefPlusNref = 2,
    /// Deform & transform: __WPref + __WNref
    DeformTransformWprefPlusWnref = 3,
}

